import React, { useEffect } from 'react';
import { Linking, View, Text } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

const ProfileScreen = ({ route }) => {
  const userId = route.params.id;
  return (
    <View>
      <Text>Profile Screen for User ID: {userId}</Text>
    </View>
  );
};

const PaymentConfirmScreen = () => {
  return (
    <View>
      <Text>Payment Confirmation Screen</Text>
    </View>
  );
};

const App = () => {
  useEffect(() => {
    const handleDeepLink = async (event) => {
      if (event.url) {
        const { scheme, path, params } = Linking.parse(event.url);

        if (scheme === 'myapp') {
          switch (path) {
            case 'profile':
              if (params && params.id) {
                navigation.navigate('Profile', { id: params.id });
              }
              break;
            case 'payment/confirm':
              navigation.navigate('PaymentConfirm');
              break;
            default:
              console.warn(`Unhandled deep link path: ${path}`);
          }
        }
      }
    };

    const linking = {
      prefixes: ['myapp://'],
      config: {
        screens: {
          Profile: 'profile/:id',
          PaymentConfirm: 'payment/confirm',
        },
      },
    };

    Linking.addEventListener('url', handleDeepLink);

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, []);

  return (
    <NavigationContainer linking={linking}>
      <Stack.Navigator>
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

export default App;